// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./ReactiveRewardEngine.sol";

/**
 * @title EventHandler
 * @dev Somnia Reactivity SDK integration - handles push-based reactions
 * Listens to EventTriggered events from ReactiveRewardEngine
 * Automatically executes matching rules without any external keeper
 * 
 * In production, this would inherit from SomniaEventHandler precompile:
 * contract EventHandler is SomniaEventHandler {
 *   function _onEvent(uint256 subscriptionId, address publisher, bytes calldata inputs) internal override { ... }
 * }
 * 
 * For MVP, we simulate the behavior with manual rule matching
 */

contract EventHandler {

    ReactiveRewardEngine public rewardEngine;
    address public admin;

    // Subscription tracking (in real Somnia, this is handled by precompile)
    mapping(uint256 => RuleSubscription) public subscriptions;
    uint256 public subscriptionCounter;

    struct RuleSubscription {
        uint256 subscriptionId;
        uint256 ruleId;
        string eventName;
        bool active;
    }

    event SubscriptionCreated(
        uint256 indexed subscriptionId,
        uint256 indexed ruleId,
        string eventName
    );

    event RuleExecuted(
        uint256 indexed ruleId,
        address indexed user,
        string eventName,
        uint256 timestamp
    );

    event ReactionProcessed(
        address indexed user,
        string eventName,
        uint256 actionType,
        uint256 timestamp
    );

    // ============ Constructor ============

    constructor(address _rewardEngine) {
        require(_rewardEngine != address(0), "Invalid engine");
        rewardEngine = ReactiveRewardEngine(_rewardEngine);
        admin = msg.sender;
        subscriptionCounter = 0;
    }

    // ============ Somnia Reactivity Simulation ============

    /**
     * @dev Simulate Somnia Reactivity push: Create a subscription to a rule
     * In real Somnia: would call reactivity precompile with filter + callback
     * Here: we manually subscribe and execute when events are detected
     */
    function subscribeToRule(uint256 _ruleId, string memory _eventName) external returns (uint256) {
        require(_ruleId < rewardEngine.getRuleCounter(), "Rule not found");

        uint256 subscriptionId = subscriptionCounter++;

        subscriptions[subscriptionId] = RuleSubscription({
            subscriptionId: subscriptionId,
            ruleId: _ruleId,
            eventName: _eventName,
            active: true
        });

        emit SubscriptionCreated(subscriptionId, _ruleId, _eventName);

        return subscriptionId;
    }

    /**
     * @dev Handle event reaction (simulates Somnia's _onEvent callback)
     * In real Somnia: automatically triggered by push when event matches filter
     * Here: called when an event is detected matching a subscription
     * 
     * On real Somnia testnet, this signature would be:
     * function _onEvent(uint256 subscriptionId, address publisher, bytes calldata inputs) internal override
     * 
     * For MVP, we provide a trigger mechanism to simulate the push
     */
    function handleEventReaction(
        uint256 _subscriptionId,
        address _user,
        string memory _eventName
    ) external {
        // In production, this would be called automatically by Somnia validators
        // For MVP/demo, can be called by a keeper or manually for showcase

        require(subscriptions[_subscriptionId].active, "Subscription not active");

        RuleSubscription memory sub = subscriptions[_subscriptionId];

        // Verify event name matches subscription
        require(keccak256(abi.encodePacked(sub.eventName)) == keccak256(abi.encodePacked(_eventName)), "Event mismatch");

        // Execute the rule action
        rewardEngine.executeAction(_user, sub.ruleId);

        emit RuleExecuted(sub.ruleId, _user, _eventName, block.timestamp);
        emit ReactionProcessed(_user, _eventName, 0, block.timestamp);
    }

    /**
     * @dev Automatic push-based reaction trigger
     * On real Somnia, this happens automatically when EventTriggered event is detected
     * For MVP, this demonstrates the concept
     */
    function processEvent(
        uint256 _eventId
    ) external {
        // Retrieve event from engine
        (address user, string memory eventName, , , ) = rewardEngine.getEventTuple(_eventId);

        // Find matching subscriptions and execute
        for (uint256 i = 0; i < subscriptionCounter; i++) {
            RuleSubscription memory sub = subscriptions[i];

            if (sub.active && keccak256(abi.encodePacked(sub.eventName)) == keccak256(abi.encodePacked(eventName))) {
                // Rule matched! Execute immediately (this is the push-based reaction)
                rewardEngine.executeAction(user, sub.ruleId);
                emit RuleExecuted(sub.ruleId, user, eventName, block.timestamp);
            }
        }
    }

    // ============ Query Functions ============

    function getSubscription(uint256 _subscriptionId) external view returns (RuleSubscription memory) {
        return subscriptions[_subscriptionId];
    }

    function toggleSubscription(uint256 _subscriptionId) external {
        require(msg.sender == admin, "Only admin");
        subscriptions[_subscriptionId].active = !subscriptions[_subscriptionId].active;
    }
}

contracts/LeaderboardRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title LeaderboardRegistry
 * @dev On-chain leaderboard tracking scores, ranks, and achievements
 */
contract LeaderboardRegistry {

    // ============ Types & Storage ============

    struct PlayerStats {
        address playerAddress;
        uint256 score;
        uint256 rank;
        uint256 achievementCount;
        uint256 lastScoreUpdate;
        bool isActive;
    }

    struct Achievement {
        uint256 id;
        string name;
        string description;
        address earnedBy;
        uint256 earnedAt;
    }

    address public admin;
    address public rewardEngine;

    uint256 public totalPlayers;
    uint256 public achievementCounter;

    mapping(address => PlayerStats) public playerStats;
    mapping(uint256 => Achievement) public achievements;
    mapping(address => uint256[]) public playerAchievementIds;

    address[] public topPlayers;
    mapping(address => uint256) public playerRank;

    event PlayerRegistered(address indexed player, uint256 timestamp);
    event ScoreUpdated(address indexed player, uint256 newScore, int256 delta, uint256 timestamp);
    event RankUpdated(address indexed player, uint256 newRank, uint256 timestamp);
    event AchievementAdded(uint256 indexed achievementId, address indexed player, string name, uint256 timestamp);
    event LeaderboardUpdated(uint256 totalPlayers, uint256 timestamp);

    modifier onlyRewardEngine() {
        require(msg.sender == rewardEngine, "Only reward engine");
        _;
    }

    modifier onlyAdmin() {
        require(msg.sender == admin, "Only admin");
        _;
    }

    constructor() {
        admin = msg.sender;
        totalPlayers = 0;
        achievementCounter = 0;
    }

    function setRewardEngine(address _engine) external onlyAdmin {
        require(_engine != address(0), "Invalid engine");
        rewardEngine = _engine;
    }

    // ============ THE FIX IS HERE (Changed external to public) ============
    function registerPlayer(address _player) public {
        require(_player != address(0), "Invalid player");
        require(!playerStats[_player].isActive, "Already registered");

        playerStats[_player] = PlayerStats({
            playerAddress: _player,
            score: 0,
            rank: totalPlayers + 1,
            achievementCount: 0,
            lastScoreUpdate: block.timestamp,
            isActive: true
        });

        totalPlayers++;
        emit PlayerRegistered(_player, block.timestamp);
    }

    function updateScore(address _player, uint256 _points) external onlyRewardEngine {
        PlayerStats storage stats = playerStats[_player];

        if (!stats.isActive) {
            registerPlayer(_player);
        }

        uint256 oldScore = stats.score;
        stats.score += _points;
        stats.lastScoreUpdate = block.timestamp;

        emit ScoreUpdated(_player, stats.score, int256(_points), block.timestamp);
        _updateLeaderboard();
    }

    function awardAchievement(
        address _player,
        string memory _name,
        string memory _description
    ) external onlyRewardEngine returns (uint256) {
        // Also make sure they are registered here!
        if (!playerStats[_player].isActive) {
            registerPlayer(_player);
        }

        uint256 achievementId = achievementCounter++;

        achievements[achievementId] = Achievement({
            id: achievementId,
            name: _name,
            description: _description,
            earnedBy: _player,
            earnedAt: block.timestamp
        });

        playerAchievementIds[_player].push(achievementId);

        PlayerStats storage stats = playerStats[_player];
        if (stats.isActive) {
            stats.achievementCount++;
        }

        emit AchievementAdded(achievementId, _player, _name, block.timestamp);
        return achievementId;
    }

    function _updateLeaderboard() internal {
        emit LeaderboardUpdated(totalPlayers, block.timestamp);
    }

    function getTopPlayers(uint256 _limit) external view returns (address[] memory, uint256[] memory) {
        uint256 count = 0;
        address[] memory addresses = new address[](min(_limit, totalPlayers));
        uint256[] memory scores = new uint256[](min(_limit, totalPlayers));
        return (addresses, scores);
    }

    function getPlayerRank(address _player) external view returns (uint256) {
        return playerStats[_player].rank;
    }

    function getPlayerStats(address _player) external view returns (PlayerStats memory) {
        return playerStats[_player];
    }

    function getPlayerAchievements(address _player) external view returns (uint256[] memory) {
        return playerAchievementIds[_player];
    }

    function getAchievement(uint256 _id) external view returns (Achievement memory) {
        return achievements[_id];
    }

    function min(uint256 a, uint256 b) internal pure returns (uint256) {
        return a < b ? a : b;
    }
}

contracts/ReactiveRewardEngine.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title ReactiveRewardEngine
 * @dev Core protocol for push-based reactive rewards on Somnia Network
 * Users register rules: "When event X fires, trigger action Y"
 * Powered by Somnia Reactivity SDK (no keepers, no polling)
 */

contract ReactiveRewardEngine {
    // ============ Types & Storage ============

    enum ActionType {
        MINT_REWARD,      // Mint reward tokens
        AWARD_BADGE,      // Award achievement badge
        UPDATE_SCORE      // Update leaderboard score
    }

    struct Rule {
        uint256 id;
        string eventName;           // e.g., "SlayMonster", "CompleteWorkout"
        string condition;           // e.g., "difficulty > 2", or "always"
        ActionType actionType;
        uint256 rewardAmount;       // Tokens to mint (if MINT_REWARD)
        string badgeName;           // Badge name (if AWARD_BADGE)
        string badgeMetadata;       // Badge description/uri
        address owner;
        bool isActive;
        uint256 createdAt;
    }

    struct Event {
        uint256 id;
        address user;               // FIXED: Removed the illegal 'indexed' keyword here
        string eventName;
        string metadata;            // Custom event data as JSON
        uint256 timestamp;
        bool processed;
    }

    // ============ State ============

    address public admin;
    address public eventHandler;    // FIXED: Moved this up so the compiler sees it early

    uint256 private _ruleCounter;
    uint256 private _eventCounter;

    mapping(uint256 => Rule) public rules;
    mapping(uint256 => Event) public events;
    mapping(address => uint256) public userRewardBalance;
    mapping(address => uint256[]) public userAchievements;

    // Event history for Somnia Reactivity SDK to listen
    event RuleRegistered(
        uint256 indexed ruleId,
        address indexed owner,
        string eventName,
        uint256 rewardAmount,
        uint256 timestamp
    );

    event EventTriggered(
        uint256 indexed eventId,
        address indexed user,
        string eventName,
        string metadata,
        uint256 timestamp
    );

    event RewardMinted(
        address indexed user,
        uint256 amount,
        string reason,
        uint256 timestamp
    );

    event AchievementUnlocked(
        address indexed user,
        uint256 badgeId,
        string badgeName,
        uint256 timestamp
    );

    event ScoreUpdated(
        address indexed user,
        uint256 newScore,
        int256 delta,
        uint256 timestamp
    );

    // ============ Modifiers ============

    modifier onlyAdmin() {
        require(msg.sender == admin, "Only admin");
        _;
    }

    modifier onlyEventHandler() {
        require(msg.sender == eventHandler, "Only EventHandler");
        _;
    }

    // ============ Constructor ============

    constructor() {
        admin = msg.sender;
        _ruleCounter = 0;
        _eventCounter = 0;
    }

    // ============ Rule Management ============

    /**
     * @dev Register a new reactive rule
     * Example: When "SlayMonster" event fires, mint 50 tokens to user
     */
    function registerRule(
        string memory _eventName,
        string memory _condition,
        ActionType _actionType,
        uint256 _rewardAmount,
        string memory _badgeName,
        string memory _badgeMetadata
    ) external returns (uint256) {
        require(bytes(_eventName).length > 0, "Event name required");

        uint256 ruleId = _ruleCounter++;
        _ruleCounter = ruleId + 1;

        rules[ruleId] = Rule({
            id: ruleId,
            eventName: _eventName,
            condition: _condition,
            actionType: _actionType,
            rewardAmount: _rewardAmount,
            badgeName: _badgeName,
            badgeMetadata: _badgeMetadata,
            owner: msg.sender,
            isActive: true,
            createdAt: block.timestamp
        });

        emit RuleRegistered(
            ruleId,
            msg.sender,
            _eventName,
            _rewardAmount,
            block.timestamp
        );

        return ruleId;
    }

    /**
     * @dev User/frontend emits a custom event
     * Somnia Reactivity SDK listens for this on-chain
     * EventHandler then automatically executes matching rules
     */
    function emitCustomEvent(
        string memory _eventName,
        string memory _metadata
    ) external {
        uint256 eventId = _eventCounter;
        _eventCounter++;

        events[eventId] = Event({
            id: eventId,
            user: msg.sender,
            eventName: _eventName,
            metadata: _metadata,
            timestamp: block.timestamp,
            processed: false
        });

        emit EventTriggered(
            eventId,
            msg.sender,
            _eventName,
            _metadata,
            block.timestamp
        );
    }

    // ============ Action Execution (Called by EventHandler) ============

    /**
     * @dev Execute a reward action (called by EventHandler after rule matches)
     * This is where the actual reward logic happens
     */
    function executeAction(
        address _user,
        uint256 _ruleId
    ) external onlyEventHandler {
        require(_user != address(0), "Invalid user");
        require(_ruleId < _ruleCounter, "Rule not found");

        Rule storage rule = rules[_ruleId];
        require(rule.isActive, "Rule not active");

        if (rule.actionType == ActionType.MINT_REWARD) {
            _mintReward(_user, rule.rewardAmount, rule.eventName);
        } else if (rule.actionType == ActionType.AWARD_BADGE) {
            _awardBadge(_user, _ruleId, rule.badgeName, rule.badgeMetadata);
        } else if (rule.actionType == ActionType.UPDATE_SCORE) {
            _updateScore(_user, rule.rewardAmount);
        }
    }

    /**
     * @dev Internal: Mint reward tokens to user
     */
    function _mintReward(
        address _user,
        uint256 _amount,
        string memory _reason
    ) internal {
        userRewardBalance[_user] += _amount;

        emit RewardMinted(
            _user,
            _amount,
            _reason,
            block.timestamp
        );
    }

    /**
     * @dev Internal: Award achievement badge to user
     */
    function _awardBadge(
        address _user,
        uint256 _badgeId,
        string memory _badgeName,
        string memory _metadata
    ) internal {
        userAchievements[_user].push(_badgeId);

        emit AchievementUnlocked(
            _user,
            _badgeId,
            _badgeName,
            block.timestamp
        );
    }

    /**
     * @dev Internal: Update user score on leaderboard
     */
    function _updateScore(address _user, uint256 _deltaScore) internal {
        // Delta is passed as points to add
        // LeaderboardRegistry will handle actual rank updates
        emit ScoreUpdated(_user, userRewardBalance[_user], int256(_deltaScore), block.timestamp);
    }

    // ============ Query Functions ============

    function getRule(uint256 _ruleId) external view returns (Rule memory) {
        return rules[_ruleId];
    }

    function getEvent(uint256 _eventId) external view returns (Event memory) {
        return events[_eventId];
    }

    function getEventTuple(uint256 _eventId) external view returns (address, string memory, string memory, uint256, bool) {
        Event memory evt = events[_eventId];
        return (evt.user, evt.eventName, evt.metadata, evt.timestamp, evt.processed);
    }

    function getUserRewards(address _user) external view returns (uint256) {
        return userRewardBalance[_user];
    }

    function getUserAchievements(address _user) external view returns (uint256[] memory) {
        return userAchievements[_user];
    }

    function getRuleCounter() external view returns (uint256) {
        return _ruleCounter;
    }

    function getEventCounter() external view returns (uint256) {
        return _eventCounter;
    }

    // ============ Admin Functions ============

    function toggleRule(uint256 _ruleId) external onlyAdmin {
        require(_ruleId < _ruleCounter, "Rule not found");
        rules[_ruleId].isActive = !rules[_ruleId].isActive;
    }

    function setEventHandler(address _handler) external onlyAdmin {
        require(_handler != address(0), "Invalid handler");
        eventHandler = _handler;
    }
}

